import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"上医医国","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/上医医国.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/上医医国.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/上医医国.md"};function d(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"上医医国",tabindex:"-1"},[s("上医医国 "),e("a",{class:"header-anchor",href:"#上医医国","aria-label":'Permalink to "上医医国"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="上医医国-1" tabindex="-1">上医医国 <a class="header-anchor" href="#上医医国-1" aria-label="Permalink to &quot;上医医国&quot;">​</a></h1><p>上医医国<br> 250分<br> “上医医国，其次疾人，固医官也。”<br> 该武器采用基础远程武器中的霰弹枪模板，具有全部相关特性，但武器体积下降至2。</p><p>这把霰弹枪为手工制作的双管枪械，外部用黑色胶带缠绕固定，采用电击发（无需考虑供能），可以发射钢珠弹丸。其在不被使用时通常不会被认作是武器而被忽略，因此绝大多数情况下即使被搜身也不会被取走，这是一个无支线级心灵来源的思维控制效果。</p><p>研发（B+4000）：安培切<br> 使用这一能力需要满足以下条件。<br> 1.被你攻击的目标有着极高的地位（且至少在一国之内有着较高的影响，如首相，前首相等等）。<br> 2.被你攻击的目标有建立或掌控特定的组织（如型月杀生院祈荒建立的宗教，或某前首相建立的组织、宗教等等）。<br> 3.在满足条件2的情况下，被你攻击的目标所建立或掌控的组织对至少一国内的民众产生恶劣影响（如杀生院祈荒诱导信众自裁，进行人体实验等等，前首相借助宗教敛财导致信众家破人亡等等）。</p><p>当满足全部条件时，你可以消费一个整轮动作使用这一能力，你对目标进行一次枪械攻击，并获得以下好处：<br> *本次枪械攻击进行两次检定，取其中较高者结算。<br> *本次枪械攻击无视【闪避防御】与【神圣防御】，这是一个B级附身来源的效果。<br> *本次枪械攻击最终出目增加一半，基础武器伤害提升至28L，在攻击上获得2个额外附加成功数，具有【幻灭】特性，命中后造成【A级重伤】影响（重伤效果持续一轮，若需处理来源，视为B级创伤来源的效果）。</p><p>变体：你也可以购买斧子的版本，这将会取代上医医国的霰弹枪基础模板，改为使用基础近战武器中的斧。若如此做，则你无法研发安培切这一能力。</p><p>“丞相之病，根源在脑。需用利斧砍开脑袋，取出风涎，方可除根。”</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
